import { BrowserRouter, Routes, Route, Navigate } from "react-router-dom";

import Login from "./pages/Login";

import ProtectedRoute from "./auth/ProtectedRoute";

import AdminLayout from "../src/pages/";

import Dashboard from "./pages/admin/Dashboard";
import AddPatient from "./pages/admin/Patient/AddPatient";
import EMR from "./pages/admin/EMR/EMR";

import DoctorDashboard from "./pages/doctor/DoctorDashboard";
import NurseDashboard from "./pages/nurse/NurseDashboard";
import ReceptionDashboard from "./pages/reception/ReceptionDashboard";

export default function App() {
  return (
    <BrowserRouter>
      <Routes>

        {/* ================= LOGIN ================= */}
        <Route path="/" element={<Login />} />

        {/* ================= ADMIN ================= */}
        <Route
          path="/admin"
          element={
            <ProtectedRoute role="ADMIN">
              <AdminLayout />
            </ProtectedRoute>
          }
        >
          {/* default after login */}
          <Route index element={<Dashboard />} />

          <Route path="dashboard" element={<Dashboard />} />

          <Route
            path="patients/register"
            element={<AddPatient />}
          />

          <Route
            path="patients/visit"
            element={<div>Patient Visit Page</div>}
          />

          <Route
            path="emr"
            element={<EMR />}
          />

          <Route
            path="billing"
            element={<div>Billing Page</div>}
          />
        </Route>

        {/* ================= DOCTOR ================= */}
        <Route
          path="/doctor"
          element={
            <ProtectedRoute role="DOCTOR">
              <DoctorDashboard />
            </ProtectedRoute>
          }
        />

        {/* ================= NURSE ================= */}
        <Route
          path="/nurse"
          element={
            <ProtectedRoute role="NURSE">
              <NurseDashboard />
            </ProtectedRoute>
          }
        />

        {/* ================= RECEPTION ================= */}
        <Route
          path="/reception"
          element={
            <ProtectedRoute role="RECEPTIONIST">
              <ReceptionDashboard />
            </ProtectedRoute>
          }
        />

        {/* ================= FALLBACK ================= */}
        <Route path="*" element={<Navigate to="/" />} />

      </Routes>
    </BrowserRouter>
  );
}
